            const pixel_values = model_inputs.pixel_values[i].unsqueeze_(0);

            // Critical: Model takes BOTH text and image inputs
            const output = await this.model({ ...text_inputs, pixel_values });

            // 3. POSTPROCESSING: Use processor's post-processing method
            const processed = this.processor.image_processor.post_process_object_detection(
                output, threshold, imageSize, true
            )[0];

            const result = processed.boxes.map((box, i) => ({
                score: processed.scores[i],
                label: candidate_labels[processed.classes[i]],
                box: get_bounding_box(box, !percentage),
            }))

            result.sort((a, b) => b.score - a.score);
            if (top_k !== null) {
                result = result.slice(0, top_k);
            }
            toReturn.push(result)
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

#### **Pattern 5: Image + Text Output (ImageToTextPipeline)**
Lines 1975-2005

```javascript
export class ImageToTextPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(images, generate_kwargs = {}) {
        // 1. PREPROCESSING: Prepare images
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);
        const { pixel_values } = await this.processor(preparedImages);

        // 2. INFERENCE: Generate text from images (seq2seq generation)
        const toReturn = [];
        for (const batch of pixel_values) {
            batch.dims = [1, ...batch.dims]
            const output = await this.model.generate({ 
                inputs: batch, 
                ...generate_kwargs 
            });

            // 3. POSTPROCESSING: Decode generated token IDs to text
            const decoded = this.tokenizer.batch_decode(output, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }))
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

#### **Pattern 6: Complex Image Processing (DepthEstimationPipeline)**
Lines 3053-3094

```javascript
export class DepthEstimationPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(images) {
        // 1. PREPROCESSING
        const preparedImages = await prepareImages(images);
        const inputs = await this.processor(preparedImages);

        // 2. INFERENCE
        const { predicted_depth } = await this.model(inputs);

        // 3. POSTPROCESSING: Complex tensor manipulation
        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            const batch = predicted_depth[i];
            const [height, width] = batch.dims.slice(-2);
            const [new_width, new_height] = preparedImages[i].size;

            // Interpolate to original size
            const prediction = (await interpolate_4d(batch.view(1, 1, height, width), {
                size: [new_height, new_width],
                mode: 'bilinear',
            })).view(new_height, new_width);

            // Normalize and convert to image
            const minval = prediction.min().item();
            const maxval = prediction.max().item();
            const formatted = prediction.sub(minval).div_(maxval - minval).mul_(255).to('uint8').unsqueeze(0);
            const depth = RawImage.fromTensor(formatted);

            toReturn.push({
                predicted_depth: prediction,
                depth,
            });
        }

        return toReturn.length > 1 ? toReturn : toReturn[0];
    }
}
```

### 6. **Helper Functions for Input Preprocessing**

Lines 89-128:

```javascript
// Converts various image formats (string URLs, Blobs, canvas, RawImage) to RawImage objects
async function prepareImages(images) {
    if (!Array.isArray(images)) {
        images = [images];
    }
    return await Promise.all(images.map(x => RawImage.read(x)));
}

// Converts audio inputs to Float32Array
async function prepareAudios(audios, sampling_rate) {
    if (!Array.isArray(audios)) {
        audios = [audios];
    }
    return await Promise.all(audios.map(x => {
        if (typeof x === 'string' || x instanceof URL) {
            return read_audio(x, sampling_rate);
        } else if (x instanceof Float64Array) {
            return new Float32Array(x);
        }
        return x;
    }));
}

// Helper for bounding box formatting
function get_bounding_box(box, asInteger) {
    if (asInteger) {
        box = box.map(x => x | 0);
    }
    const [xmin, ymin, xmax, ymax] = box;
    return { xmin, ymin, xmax, ymax };
}
```

### 7. **Pipeline Factory Function**

Lines 3446-3513:

```javascript
export async function pipeline(
    task,
    model = null,
    {
        progress_callback = null,
        config = null,
        cache_dir = null,
        local_files_only = false,
        revision = 'main',
        device = null,
        dtype = null,
        subfolder = 'onnx',
        use_external_data_format = null,
        model_file_name = null,
        session_options = {},
    } = {}
) {
    // 1. Apply task aliases (e.g., 'sentiment-analysis' -> 'text-classification')
    task = TASK_ALIASES[task] ?? task;

    // 2. Get pipeline configuration from SUPPORTED_TASKS
    const pipelineInfo = SUPPORTED_TASKS[task.split('_', 1)[0]];
    if (!pipelineInfo) {
        throw Error(`Unsupported pipeline: ${task}...`)
    }

    // 3. Use default model if none specified
    if (!model) {
        model = pipelineInfo.default.model
        console.log(`No model specified. Using default model: "${model}".`);
    }

    // 4. Load model, tokenizer, and processor in parallel
    const classes = new Map([
        ['tokenizer', pipelineInfo.tokenizer],
        ['model', pipelineInfo.model],
        ['processor', pipelineInfo.processor],
    ]);

    const results = await loadItems(classes, model, pretrainedOptions);
    results.task = task;

    dispatchCallback(progress_callback, {
        'status': 'ready',
        'task': task,
        'model': model,
    });

    // 5. Instantiate pipeline class
    const pipelineClass = pipelineInfo.pipeline;
    return new pipelineClass(results);
}
```

### 8. **SUPPORTED_TASKS Registry**

Lines 3096-3390:

Each task defines:
- `pipeline`: The pipeline class to instantiate
- `model`: Auto model class(es) to load
- `tokenizer`: Optional tokenizer class
- `processor`: Optional processor class
- `default`: Default model name
- `type`: "text", "audio", "image", or "multimodal"

Example for multimodal task:

```javascript
"zero-shot-object-detection": {
    "tokenizer": AutoTokenizer,
    "pipeline": ZeroShotObjectDetectionPipeline,
    "model": AutoModelForZeroShotObjectDetection,
    "processor": AutoProcessor,
    "default": {
        "model": "Xenova/owlvit-base-patch32",
    },
    "type": "multimodal",
}
```

### 9. **Processor and Model Imports**

Lines 16-77:

```javascript
