    AutoTokenizer,
    PreTrainedTokenizer,
} from './tokenizers.js';

import {
    AutoModel,
    AutoModelForVision2Seq,  // image-to-text
    AutoModelForImageClassification,
    AutoModelForImageSegmentation,
    AutoModelForObjectDetection,
    AutoModelForZeroShotObjectDetection,  // text + image
    AutoModelForDocumentQuestionAnswering,  // text + image
    AutoModelForImageToImage,
    AutoModelForDepthEstimation,
    // ... many more
    PreTrainedModel,
} from './models.js';

import { AutoProcessor } from './models/auto/processing_auto.js';
import { Processor } from './base/processing_utils.js';

import { Callable } from './utils/generic.js';
import { softmax, max, round } from './utils/maths.js';
import { read_audio, RawAudio } from './utils/audio.js';
import { Tensor, mean_pooling, interpolate_4d, quantize_embeddings, topk } from './utils/tensor.js';
import { RawImage } from './utils/image.js';
```

### 10. **Key Design Patterns**

1. **Three-phase _call method**: preprocessing → inference → postprocessing
2. **Batch handling**: Pipelines handle both single inputs and arrays of inputs
3. **Flexible input types**: Images can be URLs, Blobs, canvas, or RawImage objects
4. **Model config access**: `this.model.config` contains id2label mappings and model-specific settings
5. **Processor flexibility**: Processors can contain image processors, tokenizers, or feature extractors
6. **Type safety**: Extensive JSDoc typedef annotations for TypeScript support
7. **Inheritance**: Specialized pipelines can inherit from other pipelines (e.g., BackgroundRemovalPipeline extends ImageSegmentationPipeline)

This is the complete pipeline architecture! All pipelines follow these established patterns, which should give you a solid foundation for understanding or creating new pipeline implementations.

