76	    const compare = (received, expected, path = "") => {
77	      if (typeof received === "number" && typeof expected === "number" && !Number.isInteger(received) && !Number.isInteger(expected)) {
78	        const pass = Math.abs(received - expected) < Math.pow(10, -numDigits);
79	        return {
80	          pass,
81	          message: () => (pass ? `✓ At path '${path}': expected ${received} not to be close to ${expected} with tolerance of ${numDigits} decimal places` : `✗ At path '${path}': expected ${received} to be close to ${expected} with tolerance of ${numDigits} decimal places`),
82	        };
83	      } else if (Array.isArray(received) && Array.isArray(expected)) {
84	        if (received.length !== expected.length) {
85	          return {
86	            pass: false,
87	            message: () => `✗ At path '${path}': array lengths differ. Received length ${received.length}, expected length ${expected.length}`,
88	          };
89	        }
90	        for (let i = 0; i < received.length; i++) {
91	          const result = compare(received[i], expected[i], `${path}[${i}]`);
92	          if (!result.pass) return result;
93	        }
94	      } else if (typeof received === "object" && typeof expected === "object" && received !== null && expected !== null) {
95	        const receivedKeys = Object.keys(received);
96	        const expectedKeys = Object.keys(expected);
97	        if (receivedKeys.length !== expectedKeys.length) {
98	          return {
99	            pass: false,
100	            message: () => `✗ At path '${path}': object keys length differ. Received keys: ${JSON.stringify(receivedKeys)}, expected keys: ${JSON.stringify(expectedKeys)}`,
101	          };
102	        }
103	        for (const key of receivedKeys) {
104	          if (!expected.hasOwnProperty(key)) {
105	            return {
106	              pass: false,
107	              message: () => `✗ At path '${path}': key '${key}' found in received but not in expected`,
108	            };
109	          }
110	          const result = compare(received[key], expected[key], `${path}.${key}`);
111	          if (!result.pass) return result;
112	        }
113	      } else {
114	        const pass = received === expected;
115	        return {
116	          pass,
117	          message: () => (pass ? `✓ At path '${path}': expected ${JSON.stringify(received)} not to equal ${JSON.stringify(expected)}` : `✗ At path '${path}': expected ${JSON.stringify(received)} to equal ${JSON.stringify(expected)}`),
118	        };
119	      }
120	      return { pass: true };
121	    };
122	
