export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text = null, generate_kwargs = {}) {

        const isBatched = Array.isArray(images) && Array.isArray(images[0]);
        if (!isBatched) {
            images = [images];
            if (text && !Array.isArray(text)) {
                text = [text];
            }
        }

        const toReturn = [];
        const textList = text ? (Array.isArray(text) ? text : [text]) : null;

        for (let i = 0; i < images.length; ++i) {
            const preparedImages = await prepareImages(images[i]);
            const currentText = textList ? textList[i] : null;

            // Call processor with images and text
            const inputs = currentText
                ? await this.processor(preparedImages, currentText)
                : await this.processor(preparedImages);

            const output = await this.model.generate({ ...inputs, ...generate_kwargs });
            const decoded = this.tokenizer.batch_decode(/** @type {Tensor} */(output), {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }));
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
